-- Demo members: higienizar contatos para AD Caxias do Sul (Congregação Jardim América).
-- Atualiza somente membros demo da org 11111111-0000-0000-0000-000000000004.
-- IDs fixos 22222222-0000-0000-0000-000000000001..017.
-- Não altera documents, group_members, schedule_assignments nem outras tabelas.

DO $$
DECLARE
  v_congr uuid := '11111111-0000-0000-0000-000000000004';
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM public.members
    WHERE organization_id = v_congr
      AND id = '22222222-0000-0000-0000-000000000001'
  ) THEN
    RAISE NOTICE 'members AD Caxias update skipped: demo member not found';
    RETURN;
  END IF;

  UPDATE public.members
  SET
    phone = REPLACE(phone, '(11)', '(54)'),
    updated_at = now()
  WHERE organization_id = v_congr
    AND id IN (
      '22222222-0000-0000-0000-000000000001',
      '22222222-0000-0000-0000-000000000002',
      '22222222-0000-0000-0000-000000000003',
      '22222222-0000-0000-0000-000000000004',
      '22222222-0000-0000-0000-000000000005',
      '22222222-0000-0000-0000-000000000006',
      '22222222-0000-0000-0000-000000000007',
      '22222222-0000-0000-0000-000000000008',
      '22222222-0000-0000-0000-000000000009',
      '22222222-0000-0000-0000-000000000010',
      '22222222-0000-0000-0000-000000000011',
      '22222222-0000-0000-0000-000000000012',
      '22222222-0000-0000-0000-000000000013',
      '22222222-0000-0000-0000-000000000014',
      '22222222-0000-0000-0000-000000000015',
      '22222222-0000-0000-0000-000000000016',
      '22222222-0000-0000-0000-000000000017'
    )
    AND phone LIKE '(11)%';

  UPDATE public.members
  SET
    email = REPLACE(REPLACE(email, '@ibca.com.br', '@adcaxias.org.br'), '@ibca.com', '@adcaxias.org.br'),
    updated_at = now()
  WHERE organization_id = v_congr
    AND id IN (
      '22222222-0000-0000-0000-000000000001',
      '22222222-0000-0000-0000-000000000002',
      '22222222-0000-0000-0000-000000000003',
      '22222222-0000-0000-0000-000000000004',
      '22222222-0000-0000-0000-000000000005',
      '22222222-0000-0000-0000-000000000006',
      '22222222-0000-0000-0000-000000000007',
      '22222222-0000-0000-0000-000000000008',
      '22222222-0000-0000-0000-000000000009',
      '22222222-0000-0000-0000-000000000010',
      '22222222-0000-0000-0000-000000000011',
      '22222222-0000-0000-0000-000000000012',
      '22222222-0000-0000-0000-000000000013',
      '22222222-0000-0000-0000-000000000014',
      '22222222-0000-0000-0000-000000000015',
      '22222222-0000-0000-0000-000000000016',
      '22222222-0000-0000-0000-000000000017'
    )
    AND email ILIKE '%@ibca.%';

  UPDATE public.members
  SET
    city = 'Caxias do Sul',
    state = 'RS',
    updated_at = now()
  WHERE organization_id = v_congr
    AND id IN (
      '22222222-0000-0000-0000-000000000001',
      '22222222-0000-0000-0000-000000000002',
      '22222222-0000-0000-0000-000000000003',
      '22222222-0000-0000-0000-000000000004',
      '22222222-0000-0000-0000-000000000005',
      '22222222-0000-0000-0000-000000000006',
      '22222222-0000-0000-0000-000000000007',
      '22222222-0000-0000-0000-000000000008',
      '22222222-0000-0000-0000-000000000009',
      '22222222-0000-0000-0000-000000000010',
      '22222222-0000-0000-0000-000000000011',
      '22222222-0000-0000-0000-000000000012',
      '22222222-0000-0000-0000-000000000013',
      '22222222-0000-0000-0000-000000000014',
      '22222222-0000-0000-0000-000000000015',
      '22222222-0000-0000-0000-000000000016',
      '22222222-0000-0000-0000-000000000017'
    )
    AND (city IS DISTINCT FROM 'Caxias do Sul' OR state IS DISTINCT FROM 'RS');
END $$;
